const isLoopbackHost = (host) => {
	if (!host || host.length === 0) return true;
	return host === "localhost" || host === "127.0.0.1" || host === "::1" || host === "[::1]" || host.startsWith("127.");
};
const isWildcardHost = (host) => host === "0.0.0.0" || host === "::" || host === "[::]";
const formatHostForUrl = (host) => host.includes(":") && !host.startsWith("[") ? `[${host}]` : host;
const normalizeHost = (host) => host.startsWith("[") && host.endsWith("]") ? host.slice(1, -1) : host;
const isIpv4Family = (family) => family === "IPv4" || family === 4;
const isIpv6Family = (family) => family === "IPv6" || family === 6;
const resolveHeadlessConnectionHost = (host, interfaces = (0, node_os.networkInterfaces)()) => {
	if (!host) return "localhost";
	if (!isWildcardHost(host)) return normalizeHost(host);
	const interfaceEntries = Object.values(interfaces).flatMap((entries) => entries ?? []);
	const externalIpv4 = interfaceEntries.find((entry) => !entry.internal && isIpv4Family(entry.family));
	if (externalIpv4) return externalIpv4.address;
	const externalIpv6 = interfaceEntries.find((entry) => !entry.internal && isIpv6Family(entry.family));
	return externalIpv6 ? normalizeHost(externalIpv6.address) : "localhost";
};
const resolveHeadlessConnectionString = (host, port, interfaces = (0, node_os.networkInterfaces)()) => {
	return `http://${formatHostForUrl(resolveHeadlessConnectionHost(host, interfaces))}:${port}`;
};
const resolveListeningPort = (address, fallbackPort) => {
	if (typeof address === "object" && address !== null && "port" in address && typeof address.port === "number") return address.port;
	return fallbackPort;
};
const buildPairingUrl = (connectionString, token) => {
	const url = new URL(connectionString);
	url.pathname = "/pair";
	url.searchParams.delete("token");
	url.hash = new URLSearchParams([["token", token]]).toString();
	return url.toString();
};
const renderTerminalQrCode = (value, margin = 2) => {
	const qrCode = QrCode.encodeText(value, QrCode.Ecc.MEDIUM);
	const rows = [];
	const isDark = (x, y) => x >= 0 && x < qrCode.size && y >= 0 && y < qrCode.size && qrCode.getModule(x, y);
	for (let y = -margin; y < qrCode.size + margin; y += 2) {
		let row = "";
		for (let x = -margin; x < qrCode.size + margin; x += 1) {
			const topDark = isDark(x, y);
			const bottomDark = isDark(x, y + 1);
			row += topDark ? bottomDark ? "█" : "▀" : bottomDark ? "▄" : " ";
		}
		rows.push(row);
	}
	return rows.join("\n");
};
const formatHeadlessServeOutput = (accessInfo) => [
	"T3 Code server is ready.",
	`Connection string: ${accessInfo.connectionString}`,
	`Token: ${accessInfo.token}`,
	`Pairing URL: ${accessInfo.pairingUrl}`,
	"",
	renderTerminalQrCode(accessInfo.pairingUrl),
	""
].join("\n");
const issueHeadlessServeAccessInfo = effect.Effect.fn("issueHeadlessServeAccessInfo")(function* () {
	const serverConfig = yield* ServerConfig;
	const httpServer = yield* effect_unstable_http.HttpServer.HttpServer;
	const serverAuth = yield* ServerAuth;
	const connectionString = resolveHeadlessConnectionString(serverConfig.host, resolveListeningPort(httpServer.address, serverConfig.port));
	const issued = yield* serverAuth.issuePairingCredential({ role: "owner" });
	return {
		connectionString,
		token: issued.credential,
		pairingUrl: buildPairingUrl(connectionString, issued.credential)
	};
});

